import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-008 — Lambert solver in Web Worker","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-008.md","filePath":"adr/ADR-008.md"}'),n={name:"adr/ADR-008.md"};function s(i,e,l,c,d,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-008-—-lambert-solver-in-web-worker" tabindex="-1">ADR-008 — Lambert solver in Web Worker <a class="header-anchor" href="#adr-008-—-lambert-solver-in-web-worker" aria-label="Permalink to &quot;ADR-008 — Lambert solver in Web Worker&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-01 TA anchor · §components/lambert-worker · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The porkchop plot requires computing 11,200 Lambert solutions (112 departure × 100 arrival date combinations). Each solution requires an iterative solver. Running this on the main thread blocks the UI for several seconds on slow hardware.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The Lambert solver runs in a dedicated Web Worker (<code>src/workers/lambert.worker.js</code>). The main thread posts a message with the date range and step counts; the worker computes the full grid and posts back the result.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The Lambert computation is pure — no DOM access, no state mutation, no shared memory required. Web Workers are the correct tool. The main thread remains responsive (animations continue, user can interact with the nav) while the computation runs.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Main thread computation — simplest implementation; blocks UI for 1-3 seconds on first load of plan screen. Unacceptable.</li><li>WASM solver — faster computation; adds build complexity and a WASM dependency. Not needed; the JS solver is fast enough in a worker.</li><li>Precompute at build time — bakes in a fixed date range; can&#39;t support arbitrary user-selected ranges.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: main thread stays responsive; solver can be cancelled and restarted if user changes date range. Negative: Worker message passing adds complexity; error handling across Worker boundary requires care. See RFC-003 for open questions.</p>',12)])])}const p=a(n,[["render",s]]);export{m as __pageData,p as default};
